LOG_FILE = os.path.join("logs",
    f"replay-{datetime.datetime.now().strftime('%Y%m%d-%H%M%S')}.log")
os.makedirs("logs", exist_ok=True)

def log(msg):
    ts = datetime.datetime.now().strftime("%H:%M:%S.%f")[:-3]
    line = f"[{ts}] {msg}"
    print(line, flush=True)
    with open(LOG_FILE, "a") as _f:
        _f.write(line + "\n")

# Create HID event source (mimics real hardware)
_src = CGEventSourceCreate(kCGEventSourceStateHIDSystemState)

def _post(e):
    CGEventSetSource(e, _src)
    CGEventPost(kCGHIDEventTap, e)

def mouse_move(x, y):
    e = CGEventCreateMouseEvent(_src, kCGEventMouseMoved, (x, y), kCGMouseButtonLeft)
    CGEventPost(kCGHIDEventTap, e)

def mouse_click(x, y):
    e_down = CGEventCreateMouseEvent(_src, kCGEventLeftMouseDown, (x, y), kCGMouseButtonLeft)
    e_up   = CGEventCreateMouseEvent(_src, kCGEventLeftMouseUp, (x, y), kCGMouseButtonLeft)
    CGEventPost(kCGHIDEventTap, e_down)
    time.sleep(0.05)
    CGEventPost(kCGHIDEventTap, e_up)

def mouse_rclick(x, y):
    e_down = CGEventCreateMouseEvent(_src, kCGEventRightMouseDown, (x, y), kCGMouseButtonRight)
    e_up   = CGEventCreateMouseEvent(_src, kCGEventRightMouseUp, (x, y), kCGMouseButtonRight)
    CGEventPost(kCGHIDEventTap, e_down)
    time.sleep(0.05)
    CGEventPost(kCGHIDEventTap, e_up)

def do_scroll(dy=0, dx=0):
    """Smart scroll: auto-amplifies line-unit values to pixels."""
    PIXELS_PER_LINE = 40
    py_dy = dy * PIXELS_PER_LINE if abs(dy) <= 10 and dy != 0 else dy
    py_dx = dx * PIXELS_PER_LINE if abs(dx) <= 10 and dx != 0 else dx
    if py_dy != 0:
        e = CGEventCreateScrollWheelEvent(_src, kCGScrollEventUnitPixel, 1, int(py_dy))
        CGEventPost(kCGHIDEventTap, e)
    if py_dx != 0:
        e = CGEventCreateScrollWheelEvent(_src, kCGScrollEventUnitPixel, 2, int(py_dx), 0)
        CGEventPost(kCGHIDEventTap, e)

